// CRITIC ROTO: solo revisa que el JSON tenga los campos esperados.
// NUNCA compara el monto contra ninguna politica real. Por eso es un echo chamber.
let raw = $input.first().json.output || '';
let data;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  data = JSON.parse(match ? match[0] : raw);
} catch (e) {
  return [{ json: { resultado: 'RECHAZADO', motivo: 'JSON invalido', raw } }];
}

const camposOk = ['fecha', 'monto', 'categoria'].every(c => c in data);

return [{
  json: {
    ...data,
    resultado: camposOk ? 'APROBADO' : 'RECHAZADO',
    motivo_critic: camposOk
      ? 'El JSON tiene fecha, monto y categoria. Formato valido.'
      : 'Faltan campos obligatorios.'
  }
}];
